function exportSheetToCsvFiles_(sheetId, destFolder, baseName) {
  const ss = SpreadsheetApp.openById(sheetId);
  const sheets = ss.getSheets();

  sheets.forEach(sh => {
    const values = sh.getDataRange().getDisplayValues();
    const csv = values.map(row => row.map(csvEscape_).join(",")).join("\n");

    const tabName = sanitizeFilename_(sh.getName());
    const fileName = sanitizeFilename_(baseName) + `__SHEET_${tabName}.csv`;
    destFolder.createFile(fileName, csv, MimeType.CSV);
  });
}

